// resources/js/Components/Notifications/NotificationDropdown.tsx
import { CheckIcon } from '@heroicons/react/24/outline';

import { Link, router } from '@inertiajs/react';

interface NotificationItem {
    id: number;
    type: string;
    title: string;
    message: string;
    link: string | null;
    created_at: string;
    read_at: string | null;
}

interface Props {
    notifications: NotificationItem[];
    onMarkAsRead: (id: number) => void;
    onMarkAllAsRead: () => void;
    onClose: () => void;
}

const NotificationDropdown = ({ notifications, onMarkAsRead, onMarkAllAsRead, onClose }: Props) => {
    const handleClick = (notification: NotificationItem) => {
        if (!notification.read_at) {
            router.post(`/admin/notifications/${notification.id}/read`, {}, { preserveScroll: true });
            onMarkAsRead(notification.id);
        }
        onClose();
    };

    const handleMarkAllAsRead = () => {
        router.post('/admin/notifications/read-all', {}, { preserveScroll: true });
        onMarkAllAsRead();
    };

    return (
        <div className="absolute right-0 mt-2 w-80 bg-white rounded-xl shadow-lg border border-gray-100 z-50 max-h-96 overflow-y-auto">
            <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100 sticky top-0 bg-white">
                <h3 className="text-sm font-semibold text-gray-900">Notifications</h3>
                <button
                    onClick={handleMarkAllAsRead}
                    className="text-xs text-cab-blue hover:text-cab-dark flex items-center gap-1"
                >
                    <CheckIcon className="w-4 h-4" />
                    Tout marquer comme lu
                </button>
            </div>

            {notifications.length === 0 ? (
                <p className="text-sm text-gray-500 text-center py-8">Aucune notification</p>
            ) : (
                <div className="divide-y divide-gray-100">
                    {notifications.map((notification) => (
                        <Link
                            key={notification.id}
                            href={notification.link || '#'}
                            onClick={() => handleClick(notification)}
                            className={`block px-4 py-3 hover:bg-gray-50 transition-colors ${
                                !notification.read_at ? 'bg-blue-50/50' : ''
                            }`}
                        >
                            <div className="flex items-start gap-2">
                                {!notification.read_at && (
                                    <span className="w-2 h-2 mt-1.5 rounded-full bg-cab-blue flex-shrink-0" />
                                )}
                                <div className="flex-1">
                                    <p className="text-sm font-medium text-gray-900">{notification.title}</p>
                                    <p className="text-xs text-gray-500 mt-0.5">{notification.message}</p>
                                    <p className="text-xs text-gray-400 mt-1">{notification.created_at}</p>
                                </div>
                            </div>
                        </Link>
                    ))}
                </div>
            )}
        </div>
    );
};

export default NotificationDropdown;
